//    「単元集約」    … 全授業ふりかえり蓄積
// ============================================================

// ---- 固定定数 ----
const SHEET_CFG     = '設定';
const SHEET_SUBJECT = '教科デフォルト';
const SHEET_UNITS   = '単元一覧';
