  // 設定シート
  if (!ss.getSheetByName(SHEET_CFG)) {
    const s = ss.insertSheet(SHEET_CFG);
    s.getRange(1,1,1,3).setValues([['キー','値','説明']]);
    s.getRange(2,1,6,3).setValues([
      ['medal_top',      '5',  'メダル上位人数（最大5）'],
      ['prompt_comment', DEFAULT_PROMPT_COMMENT, 'コメント用プロンプト'],
